//------------------------------------------------------------------------------------------------------------------------
// Script Continued Below
var x_153465_discovert = x_153465_discovert || {};

x_153465_discovert.twJS = (function() {
	"use strict";
	/* 	set your private variables and functions here. For example: 
	var privateVar = 0; 
	function private_function() {
		return ++privateVar;
	}
	*/

	var defaultSize = 'lg';
	var backdrop = 'static';
	var buttons = [];
	var footerStyle = {'display': 'block'};

	function _defaultSize(size){
		var lSize;
		// check to see if the size property passed by the caller is populated, if not return large
		if(!size || size == 'undefined' || size == 'null' || size == ''){
			lSize = defaultSize;
		} else {
			lSize = size;
		}
		return lSize;
	}

	function _defaultBackdrop(backdrop){
		var lBackdrop;
		// check to see if the size property passed by the caller is populated, if not return large
		if(!backdrop || backdrop == 'undefined' || backdrop == 'null' || backdrop == ''){
			lBackdrop = backdrop;
		} else {
			lBackdrop = backdrop;
		}
		return lBackdrop;
	}

	function _defaultButtons(buttons){
		var lButtons;
		// check to see if the size property passed by the caller is populated, if not return large
		if(!buttons || buttons == 'undefined' || buttons == 'null' || buttons.length == 0){
			lButtons = buttons;
		} else {
			lButtons = buttons;
		}
		return lButtons;
	}

	function _defaultFooterStyle(isModal, footerStyle){
		var lFooterStyle;
		// check to see if the size property passed by the caller is populated, if not return large
		if(!footerStyle || footerStyle == 'undefined' || footerStyle == 'null' || !footerStyle.display ||footerStyle.display.length == 0){
			if(!isModal || isModal == 'undefined' || isModal == 'null' || isModal.length == 0 || isModal == 'false'){
				lFooterStyle = footerStyle;
			} else {
				// if modal, but still displaying 
				lFooterStyle = {'display': 'none'};
			}
		} else {
			lFooterStyle = footerStyle;
		}
		return lFooterStyle;
	}

/* Share variables between multiple UI scripts by adding them to your scope object. For example: 
	x_153465_discovert.sharedVar = 0; 

 Then access them in your scripts the same way. For example: 
	function get_shared() {
		return x_153465_discovert.sharedVar;
	}
*/

	return {

/* set your public API here. For example:
		incrementAndReturnPrivateVar: function() {
			return _function();
		},
*/
		openDurationModal: function(spModal, title, table, sys_id) {
			spModal.open({
				title: title, // c.data.durationTitle + ': ' + obj.part.data.name,
				message: '',
				backdrop: 'static',
				widget: 'tasker_modal_additional_information',
				widgetInput: {
					table: table, // c.data.table,
					sys_id: sys_id, // obj.part.data.key,
					view: 'Duration_View',
					hideRelatedLists: true,
					omitHeader: 'true',
					hideAttachmentBtn: true,
					isModal: true
				},
				shared: {},
				size: 'lg',
				buttons: [],
				footerStyle: {'display': 'none'}
			});
		},

		openCreateModal: function(spModal, title, table, view, query) {
			spModal.open({
				title: title,
				message: '',
				backdrop: 'static',
				widget: 'discovertasker-formtab',
				widgetInput: {
					omit_icons: true,
					table: table,
					query:  query,
					sys_id: -1,
					view: view,  // NOTE, we may need to look up default
					hideRelatedLists: true,
					omitHeader: 'true',
					hideAttachmentBtn: true,
					isModal: true
				},
				shared: {},
				size: 'lg',
				buttons: [],
				footerStyle: {'display': 'none'}
			});			
		},

		openAssignmentModal: function(spModal, title, table, sys_id) {
			spModal.open({
				title: title,
				message: '',
				backdrop: 'static',
				widget: 'tasker_modal_additional_information',
				widgetInput: {
					table: table,
					sys_id: sys_id,
					view: 'Assignment_View',
					hideRelatedLists: true,
					omitHeader: 'true',
					hideAttachmentBtn: true,
					isModal: true
				},
				shared: {},
				size: 'lg',
				buttons: [],
				footerStyle: {'display': 'none'}
			});
		},

		openOperationalModal: function(spModal, title, table, sys_id) {
			spModal.open({
				title: title,
				message: '',
				backdrop: 'static',
				widget: 'tasker_modal_additional_information',
				widgetInput: {
					table: table,
					sys_id: sys_id,
					view: 'Operational_View',
					hideRelatedLists: true,
					omitHeader: 'true',
					hideAttachmentBtn: true,
					isModal: true
				},
				shared: {},
				size: 'lg',
				buttons: [],
				footerStyle: {'display': 'none'}
			});
		},

		openTreeViewModal: function(spModal, sys_id) {
			spModal.open({
				message: '',
				backdrop: 'static',
				widget: 'discovertasker-recursivetasktreegraph',
				widgetInput: {
					hide_accordion:true,
					table: "x_153465_discovert_route_task_instance",
					sys_id: sys_id,
					isModal: true
				},
				shared: {},
				size: 'lg',
				buttons: [],
				footerStyle: {'display': 'none'}
			});
		},
		// 2.8   - 2022-04-05 - raj -  STRY0117600 - Update Templates to match the UI of Org Hierarchy 
		openFormModal: function(spModal, modalProperties){
			spModal.open({
				title: modalProperties.title,
				backdrop:  _defaultBackdrop(modalProperties.backdrop),
				widget: modalProperties.widget,
				widgetInput: modalProperties.widgetInput,
				size: _defaultSize(modalProperties.size),
				buttons: _defaultButtons(modalProperties.buttons),
				shared: modalProperties.shared,
				// footer styling added to handle proper styling for modal forms
				footerStyle: _defaultFooterStyle(modalProperties.widgetInput.isModal, modalProperties.footerStyle)
			});			
		},

		type:  "twJS"
	};
})();
